# This script tests parts of filter-build-webkit.
# This script runs the unittests specified in @testFiles.

use strict;
use warnings;

use English;
use FindBin;
use Test::More;
use lib File::Spec->catdir($FindBin::Bin, "..");
use LoadAsModule qw(FilterBuildCyberKit filter-build-webkit);

sub description($);

@FilterBuildCyberKit::EXPORT_OK = qw(shouldIgnoreLine);
FilterBuildCyberKit->import(@FilterBuildCyberKit::EXPORT_OK);

